@@ -153,13 +153,6 @@ func Run(config *RunConfig) error {
 	// Add name
 	args = append(args, "--name", containerName)

-	// On macOS, run as host user to avoid permission issues with mounted volumes
-	// Docker Desktop on macOS uses osxfs which maps file ownership automatically,
-	// but only when the container user matches the host user UID
-	if !isLinux {
-		args = append(args, "--user", fmt.Sprintf("%s:%s", currentUser.Uid, currentUser.Gid))
-	}
-
 	// Add mounts with or without idmap based on OS
 	homeDir := currentUser.HomeDir

@@ -170,7 +163,7 @@ func Run(config *RunConfig) error {
 			homeDir, devConfig.RemoteUser, currentUser.Uid, currentUser.Uid, currentUser.Gid, currentUser.Gid,
 		))
 	} else {
-		// macOS - no idmap support
+		// macOS - Docker Desktop handles permissions automatically
 		args = append(args, "-v", fmt.Sprintf("%s/.claude:/home/%s/.claude", homeDir, devConfig.RemoteUser))
 	}

@@ -191,19 +184,9 @@ func Run(config *RunConfig) error {
 	// Add environment variables
 	// Copy host environment
 	for _, env := range os.Environ() {
-		// On macOS, skip HOME since we need to set it to match the container mount path
-		if !isLinux && strings.HasPrefix(env, "HOME=") {
-			continue
-		}
 		args = append(args, "-e", env)
 	}

-	// Set HOME appropriately
-	if !isLinux {
-		// On macOS, set HOME to match where we mounted .claude
-		args = append(args, "-e", fmt.Sprintf("HOME=/home/%s", devConfig.RemoteUser))
-	}
-
 	// Add IS_SANDBOX
 	args = append(args, "-e", "IS_SANDBOX=1")
